+/**
+ * Webhook notification adapter.
+ *
+ * Implements the NotificationAdapter interface for the 'webhook' channel.
+ * Formats notification payloads as JSON and POSTs them to a configured URL.
+ * In-memory transport is used for testing; the transport method can be
+ * overridden for production use.
+ */
+
+import type { NotificationAdapter } from './notification.adapter.js';
+import type {
+  NotificationPayload,
+  NotificationResult,
+} from '../models/notification.js';
+import { Logger } from '../utils/logger.js';
+
+export interface WebhookConfig {
+  /** The URL to POST webhook payloads to. */
+  url: string;
+  /** Optional secret for signing payloads (e.g. HMAC). */
+  secret?: string;
+  /** Maximum retries on transient failure. */
+  maxRetries: number;
+  /** Request timeout in milliseconds. */
+  timeoutMs: number;
+}
+
+const defaultWebhookConfig: WebhookConfig = {
+  url: '',
+  maxRetries: 3,
+  timeoutMs: 5000,
+};
+
+export interface WebhookPayload {
+  event: string;
+  recipient: string;
+  subject: string;
+  body: string;
+  metadata?: Record<string, unknown>;
+  timestamp: string;
+}
+
+export interface SentWebhookRecord {
+  url: string;
+  payload: WebhookPayload;
+  sentAt: Date;
+  attempts: number;
+}
+
+function isValidUrl(url: string): boolean {
+  return /^https?:\/\/.+/.test(url);
+}
+
+export class WebhookAdapter implements NotificationAdapter {
+  readonly channel = 'webhook' as const;
+  private logger = new Logger('WebhookAdapter');
+  private sentWebhooks: SentWebhookRecord[] = [];
+  private config: WebhookConfig;
+
+  constructor(config: Partial<WebhookConfig> & Pick<WebhookConfig, 'url'>) {
+    this.config = { ...defaultWebhookConfig, ...config };
+  }
+
+  async send(payload: NotificationPayload): Promise<NotificationResult> {
+    // Validate URL
+    if (!this.config.url || !isValidUrl(this.config.url)) {
+      this.logger.error(`Invalid webhook URL: ${this.config.url}`);
+      return {
+        success: false,
+        notificationId: '',
+        channel: 'webhook',
+        error: `Invalid webhook URL: ${this.config.url}`,
+      };
+    }
+
+    // Validate recipient
+    if (!payload.recipient) {
+      this.logger.error('Missing recipient in webhook payload');
+      return {
+        success: false,
+        notificationId: '',
+        channel: 'webhook',
+        error: 'Missing recipient in webhook payload',
+      };
+    }
+
+    // Format the webhook payload
+    const webhookPayload = this.formatPayload(payload);
+
+    // Attempt delivery with retries
+    let lastError: string | undefined;
+    for (let attempt = 1; attempt <= this.config.maxRetries; attempt++) {
+      try {
+        await this.transport(this.config.url, webhookPayload);
+
+        this.sentWebhooks.push({
+          url: this.config.url,
+          payload: webhookPayload,
+          sentAt: new Date(),
+          attempts: attempt,
+        });
+
+        this.logger.info(
+          `Webhook delivered to ${this.config.url} for ${payload.recipient} (attempt ${attempt})`,
+        );
+
+        return {
+          success: true,
+          notificationId: '',
+          channel: 'webhook',
+        };
+      } catch (err) {
+        lastError = err instanceof Error ? err.message : String(err);
+        this.logger.warn(
+          `Webhook send attempt ${attempt}/${this.config.maxRetries} failed: ${lastError}`,
+        );
+      }
+    }
+
+    this.logger.error(
+      `Webhook delivery failed after ${this.config.maxRetries} attempts to ${this.config.url}: ${lastError}`,
+    );
+
+    return {
+      success: false,
+      notificationId: '',
+      channel: 'webhook',
+      error: `Delivery failed after ${this.config.maxRetries} attempts: ${lastError}`,
+    };
+  }
+
+  /**
+   * Format a notification payload into the webhook JSON structure.
+   */
+  formatPayload(payload: NotificationPayload): WebhookPayload {
+    return {
+      event: payload.type,
+      recipient: payload.recipient,
+      subject: payload.subject,
+      body: payload.body,
+      metadata: payload.metadata,
+      timestamp: new Date().toISOString(),
+    };
+  }
+
+  /**
+   * The transport layer. In-memory by default; override for production.
+   * Production implementations would use fetch() or an HTTP client.
+   */
+  protected async transport(_url: string, _payload: WebhookPayload): Promise<void> {
+    // In-memory transport — no-op. Production implementations would POST
+    // the JSON payload to the URL.
+  }
+
+  /**
+   * Get all successfully sent webhooks (useful for testing).
+   */
+  getSentWebhooks(): SentWebhookRecord[] {
+    return [...this.sentWebhooks];
+  }
+
+  /**
+   * Clear sent webhooks (useful for testing).
+   */
+  clearSentWebhooks(): void {
+    this.sentWebhooks = [];
+  }
+
+  /**
+   * Get the current configuration.
+   */
+  getConfig(): Readonly<WebhookConfig> {
+    return { ...this.config };
+  }
+}

