/**
 * Webhook notification adapter.
 *
 * Implements the NotificationAdapter interface for the 'webhook' channel.
 * Formats notification payloads as JSON and POSTs them to a configured URL.
 * In-memory transport is used for testing; the transport method can be
 * overridden for production use.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type {
  NotificationPayload,
  NotificationResult,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface WebhookConfig {
  /** The URL to POST webhook payloads to. */
  url: string;
  /** Optional secret for signing payloads (e.g. HMAC). */
  secret?: string;
  /** Maximum retries on transient failure. */
  maxRetries: number;
  /** Request timeout in milliseconds. */
  timeoutMs: number;
}

const defaultWebhookConfig: WebhookConfig = {
  url: '',
  maxRetries: 3,
  timeoutMs: 5000,
};

export interface WebhookPayload {
  event: string;
  recipient: string;
  subject: string;
  body: string;
  metadata?: Record<string, unknown>;
  timestamp: string;
}

export interface SentWebhookRecord {
  url: string;
  payload: WebhookPayload;
  sentAt: Date;
  attempts: number;
}

function isValidUrl(url: string): boolean {
  try {
    const parsed = new URL(url);
    return parsed.protocol === 'http:' || parsed.protocol === 'https:';
  } catch {
    return false;
  }
}

export class WebhookAdapter implements NotificationAdapter {
  readonly channel = 'webhook' as const;
  private logger = new Logger('WebhookAdapter');
  private sentWebhooks: SentWebhookRecord[] = [];
  private config: WebhookConfig;

  constructor(config: Partial<WebhookConfig> & Pick<WebhookConfig, 'url'>) {
    this.config = { ...defaultWebhookConfig, ...config };
  }

  async send(payload: NotificationPayload): Promise<NotificationResult> {
    // Validate URL
    if (!this.config.url || !isValidUrl(this.config.url)) {
      this.logger.error(`Invalid webhook URL: ${this.config.url}`);
      return {
        success: false,
        notificationId: '',
        channel: 'webhook',
        error: `Invalid webhook URL: ${this.config.url}`,
      };
    }

    // Validate recipient
    if (!payload.recipient) {
      this.logger.error('Missing recipient in webhook payload');
      return {
        success: false,
        notificationId: '',
        channel: 'webhook',
        error: 'Missing recipient in webhook payload',
      };
    }

    // Format the webhook payload
    const webhookPayload = this.formatPayload(payload);

    // Attempt delivery with retries
    let lastError: string | undefined;
    for (let attempt = 1; attempt <= this.config.maxRetries; attempt++) {
      try {
        await this.transport(this.config.url, webhookPayload);

        this.sentWebhooks.push({
          url: this.config.url,
          payload: webhookPayload,
          sentAt: new Date(),
          attempts: attempt,
        });

        this.logger.info(
          `Webhook delivered to ${this.config.url} for ${payload.recipient} (attempt ${attempt})`,
        );

        return {
          success: true,
          notificationId: '',
          channel: 'webhook',
        };
      } catch (err) {
        lastError = err instanceof Error ? err.message : String(err);
        this.logger.warn(
          `Webhook send attempt ${attempt}/${this.config.maxRetries} failed: ${lastError}`,
        );
      }
    }

    this.logger.error(
      `Webhook delivery failed after ${this.config.maxRetries} attempts to ${this.config.url}: ${lastError}`,
    );

    return {
      success: false,
      notificationId: '',
      channel: 'webhook',
      error: `Delivery failed after ${this.config.maxRetries} attempts: ${lastError}`,
    };
  }

  /**
   * Format a notification payload into the webhook JSON structure.
   */
  formatPayload(payload: NotificationPayload): WebhookPayload {
    return {
      event: payload.type,
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      metadata: payload.metadata,
      timestamp: new Date().toISOString(),
    };
  }

  /**
   * The transport layer. In-memory by default; override for production.
   * Production implementations would use fetch() or an HTTP client.
   */
  protected async transport(_url: string, _payload: WebhookPayload): Promise<void> {
    // In-memory transport — no-op. Production implementations would POST
    // the JSON payload to the URL.
  }

  /**
   * Get all successfully sent webhooks (useful for testing).
   */
  getSentWebhooks(): SentWebhookRecord[] {
    return [...this.sentWebhooks];
  }

  /**
   * Clear sent webhooks (useful for testing).
   */
  clearSentWebhooks(): void {
    this.sentWebhooks = [];
  }

  /**
   * Get the current configuration.
   */
  getConfig(): Readonly<WebhookConfig> {
    return { ...this.config };
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { WebhookAdapter } from '../../src/adapters/webhook.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides: Partial<NotificationPayload> = {}): NotificationPayload {
  return {
    recipient: 'user-123',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    type: 'order:confirmation',
    channel: 'webhook',
    ...overrides,
  };
}

describe('WebhookAdapter', () => {
  let adapter: WebhookAdapter;

  beforeEach(() => {
    adapter = new WebhookAdapter({ url: 'https://example.com/webhooks' });
  });

  describe('channel', () => {
    it('should report webhook as its channel', () => {
      expect(adapter.channel).toBe('webhook');
    });
  });

  describe('send', () => {
    it('should send a webhook successfully', async () => {
      const result = await adapter.send(makePayload());

      expect(result.success).toBe(true);
      expect(result.channel).toBe('webhook');
      expect(result.error).toBeUndefined();
    });

    it('should store sent webhooks for retrieval', async () => {
      await adapter.send(makePayload());

      const sent = adapter.getSentWebhooks();
      expect(sent).toHaveLength(1);
      expect(sent[0]!.url).toBe('https://example.com/webhooks');
      expect(sent[0]!.payload.recipient).toBe('user-123');
      expect(sent[0]!.payload.event).toBe('order:confirmation');
      expect(sent[0]!.payload.subject).toContain('Order Confirmation');
      expect(sent[0]!.sentAt).toBeInstanceOf(Date);
      expect(sent[0]!.attempts).toBe(1);
    });

    it('should reject invalid webhook URL', async () => {
      const badAdapter = new WebhookAdapter({ url: 'not-a-url' });
      const result = await badAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid webhook URL');
      expect(badAdapter.getSentWebhooks()).toHaveLength(0);
    });

    it('should reject empty webhook URL', async () => {
      const badAdapter = new WebhookAdapter({ url: '' });
      const result = await badAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid webhook URL');
    });

    it('should reject missing recipient', async () => {
      const result = await adapter.send(makePayload({ recipient: '' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Missing recipient');
    });

    it('should use custom config when provided', async () => {
      const customAdapter = new WebhookAdapter({
        url: 'https://hooks.example.com/notify',
        secret: 'my-secret',
        timeoutMs: 10000,
      });

      await customAdapter.send(makePayload());

      const sent = customAdapter.getSentWebhooks();
      expect(sent[0]!.url).toBe('https://hooks.example.com/notify');
      expect(customAdapter.getConfig().secret).toBe('my-secret');
      expect(customAdapter.getConfig().timeoutMs).toBe(10000);
    });
  });

  describe('formatPayload', () => {
    it('should produce a WebhookPayload from a notification payload', () => {
      const formatted = adapter.formatPayload(makePayload());

      expect(formatted.event).toBe('order:confirmation');
      expect(formatted.recipient).toBe('user-123');
      expect(formatted.subject).toBe('Order Confirmation: order-1');
      expect(formatted.body).toContain('Widget x2');
      expect(formatted.timestamp).toBeDefined();
    });

    it('should include metadata when present', () => {
      const formatted = adapter.formatPayload(
        makePayload({ metadata: { orderId: 'order-1' } }),
      );

      expect(formatted.metadata).toEqual({ orderId: 'order-1' });
    });

    it('should format all notification types', () => {
      const types = [
        'order:confirmation',
        'order:status-update',
        'user:welcome',
        'user:profile-update',
      ] as const;

      for (const type of types) {
        const formatted = adapter.formatPayload(makePayload({ type }));
        expect(formatted.event).toBe(type);
      }
    });
  });

  describe('retry behavior', () => {
    it('should retry on transport failure and succeed', async () => {
      let callCount = 0;

      class FailOnceAdapter extends WebhookAdapter {
        protected async transport(): Promise<void> {
          callCount++;
          if (callCount === 1) {
            throw new Error('Connection refused');
          }
        }
      }

      const retryAdapter = new FailOnceAdapter({
        url: 'https://example.com/webhooks',
        maxRetries: 3,
      });
      const result = await retryAdapter.send(makePayload());

      expect(result.success).toBe(true);
      expect(callCount).toBe(2);
      expect(retryAdapter.getSentWebhooks()[0]!.attempts).toBe(2);
    });

    it('should fail after exhausting retries', async () => {
      class AlwaysFailAdapter extends WebhookAdapter {
        protected async transport(): Promise<void> {
          throw new Error('Server unavailable');
        }
      }

      const failAdapter = new AlwaysFailAdapter({
        url: 'https://example.com/webhooks',
        maxRetries: 2,
      });
      const result = await failAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toContain('Delivery failed after 2 attempts');
      expect(result.error).toContain('Server unavailable');
      expect(failAdapter.getSentWebhooks()).toHaveLength(0);
    });
  });

  describe('clearSentWebhooks', () => {
    it('should clear all sent webhooks', async () => {
      await adapter.send(makePayload());
      await adapter.send(makePayload({ recipient: 'user-456' }));
      expect(adapter.getSentWebhooks()).toHaveLength(2);

      adapter.clearSentWebhooks();
      expect(adapter.getSentWebhooks()).toHaveLength(0);
    });
  });

  describe('getConfig', () => {
    it('should return a copy of the config', () => {
      const config = adapter.getConfig();
      expect(config.url).toBe('https://example.com/webhooks');
      expect(config.maxRetries).toBe(3);
      expect(config.timeoutMs).toBe(5000);
    });
  });
});

